"use strict";(()=>{var a=class{COMPONENT_SELECTOR='dialog[data-el="content-modal"]';PREV_BTN_SELECTOR='[data-slider-el="nav-prev"]';NEXT_BTN_SELECTOR='[data-slider-el="nav-next"]';SCROLL_CONTAINER_SELECTOR='[data-el="content-modal-scroll-container"]';isStorySlider=!1;constructor(){this.init()}init(){document.querySelectorAll(this.COMPONENT_SELECTOR).forEach(t=>{this.isStorySlider=t.getAttribute("data-modal-type")==="stories",this.initSlider(t)})}initSlider(e){let t=e.querySelector(this.PREV_BTN_SELECTOR),r=e.querySelector(this.NEXT_BTN_SELECTOR),l=e.querySelector(this.SCROLL_CONTAINER_SELECTOR);l&&(t&&t.addEventListener("click",()=>this.handleScroll(l,"prev")),r&&r.addEventListener("click",()=>this.handleScroll(l,"next")),e.addEventListener("sliderJump",s=>{let o=s.detail.direction;o&&this.handleScroll(l,o)}))}handleScroll(e,t){let r=e.getBoundingClientRect().width,l=e.scrollWidth-r,s=e.scrollLeft,n=5,o=Math.round(s/r),i=0;if(t==="next"){if(s>=l-n){if(this.isStorySlider){e.dispatchEvent(new CustomEvent("storyHandoff",{bubbles:!0,detail:{direction:"next"}}));return}i=0}else i=(o+1)*r;e.scrollTo({left:i,behavior:"smooth"})}else if(t==="prev"){if(s<=n){if(this.isStorySlider){e.dispatchEvent(new CustomEvent("storyHandoff",{bubbles:!0,detail:{direction:"prev"}}));return}i=l}else i=(o-1)*r;e.scrollTo({left:i,behavior:"smooth"})}else t==="first"?e.scrollTo({left:0,behavior:"instant"}):t==="last"&&e.scrollTo({left:l,behavior:"instant"})}};window.Webflow=window.Webflow||[];window.Webflow.push(()=>{new a});})();
